const std::vector<std::string>& GetStrategyNames()
{
    return kStrategyNames;
}

bool TryGetStrategyTemplate(const std::string& strategyName, std::string& outTemplate)
{
    const auto it = kStrategyTemplates.find(strategyName);
    if (it == kStrategyTemplates.end())
        return false;

    outTemplate = it->second;
    return true;
}

